import React, { useState, useEffect } from 'react';
import { Menu, X } from 'lucide-react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import Button from './ui/Button';

const Navbar: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 10);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavClick = (hash: string) => {
    setMobileMenuOpen(false);
    if (location.pathname !== '/') {
        navigate('/' + hash);
    } else {
        const element = document.getElementById(hash.replace('#', ''));
        if (element) {
            element.scrollIntoView({ behavior: 'smooth' });
        }
    }
  };

  const handleJoinBeta = () => {
      navigate('/login');
      setMobileMenuOpen(false);
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      scrolled ? 'bg-cream/90 backdrop-blur-md border-b border-slate-200/50 py-3' : 'bg-transparent py-6'
    }`}>
      <div className="max-w-7xl mx-auto px-6 flex items-center justify-between">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-2.5 cursor-pointer hover:opacity-80 transition-opacity" onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}>
          <div className="flex flex-col gap-0.5">
             <div className="w-5 h-2.5 bg-jam-red rounded-full"></div>
             <div className="w-5 h-2.5 bg-[#C01525] rounded-full"></div>
             <div className="w-5 h-2.5 bg-[#9E111E] rounded-full"></div>
          </div>
          <span className="text-2xl font-bold tracking-tight text-ink font-sans">Tap</span>
        </Link>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center gap-8">
          <button onClick={() => handleNavClick('#features')} className="text-sm font-medium text-slate-600 hover:text-ink transition-colors font-sans bg-transparent border-none cursor-pointer">Features</button>
          <button onClick={() => handleNavClick('#pricing')} className="text-sm font-medium text-slate-600 hover:text-ink transition-colors font-sans bg-transparent border-none cursor-pointer">Pricing</button>
          <button onClick={() => handleNavClick('#blog')} className="text-sm font-medium text-slate-600 hover:text-ink transition-colors font-sans bg-transparent border-none cursor-pointer">Blog</button>
          <Link to="/login" className="text-sm font-medium text-slate-600 hover:text-ink transition-colors font-sans">Login</Link>

          <Button variant="primary" size="sm" className="hover:scale-105 transition-transform duration-200" onClick={handleJoinBeta}>
              Join Beta
          </Button>
        </div>

        {/* Mobile Menu Toggle */}
        <button 
          className="md:hidden text-ink p-1 active:scale-90 transition-transform"
          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
        >
          {mobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu with Fade In/Out Animation */}
      <div className={`absolute top-full left-0 right-0 bg-cream border-b border-slate-200 p-6 shadow-xl md:hidden flex flex-col gap-4 transition-all duration-300 ease-in-out origin-top ${
        mobileMenuOpen 
          ? 'opacity-100 translate-y-0 pointer-events-auto' 
          : 'opacity-0 -translate-y-4 pointer-events-none'
      }`}>
         <button onClick={() => handleNavClick('#features')} className="text-left text-base font-medium text-ink py-3 border-b border-slate-100 hover:text-jam-red transition-colors bg-transparent">Features</button>
         <button onClick={() => handleNavClick('#pricing')} className="text-left text-base font-medium text-ink py-3 border-b border-slate-100 hover:text-jam-red transition-colors bg-transparent">Pricing</button>
         <button onClick={() => handleNavClick('#blog')} className="text-left text-base font-medium text-ink py-3 border-b border-slate-100 hover:text-jam-red transition-colors bg-transparent">Blog</button>
         <Link to="/login" className="text-base font-medium text-ink py-3 border-b border-slate-100 hover:text-jam-red transition-colors" onClick={() => setMobileMenuOpen(false)}>Login</Link>

        <div className="pt-2">
            <Button 
                fullWidth 
                variant="primary" 
                onClick={handleJoinBeta}
            >
                Join Beta
            </Button>
        </div>
      </div>
    </nav>
  );
};

