  };

  const removeLink = (id: string) => {
      setSiteData(prev => ({
          ...prev,
          links: prev.links.filter(l => l.id !== id)
      }));
  };

  const themeColors = {
      light: 'bg-white text-ink',
      dark: 'bg-ink text-white',
      cream: 'bg-cream text-ink'
  };

