const Builder: React.FC = () => {
  const [stage, setStage] = useState<'input' | 'loading' | 'editor'>('input');

  // Initialize state from local storage or default
  const [siteData, setSiteData] = useState<SiteData>(() => {
    const saved = localStorage.getItem('tap_builder_data');
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        console.error("Failed to parse saved data", e);
      }
    }
    return {
      name: '',
      bio: '',
      links: [],
      themeId: 'cream',
      avatarInitials: '',
      seo: { title: '', description: '' }
    };
  });

  const [activeTab, setActiveTab] = useState<'content' | 'design' | 'settings'>('content');
  const [previewDevice, setPreviewDevice] = useState<'mobile' | 'desktop'>('mobile');
  const [isPublished, setIsPublished] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);

  // Monitor online status
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Persist to local storage whenever siteData changes
  useEffect(() => {
    if (siteData.name) {
      localStorage.setItem('tap_builder_data', JSON.stringify(siteData));
    }
  }, [siteData]);

  // If we loaded data from local storage, jump to editor
  useEffect(() => {
    if (siteData.name && stage === 'input') {
      setStage('editor');
    }
  }, []);

  const handleGenerate = (name: string, desc: string) => {
    setStage('loading');

    // Simulate AI Generation
    setTimeout(() => {
      const newData: SiteData = {
        name: name,
        bio: desc,
        links: [
            { id: '1', label: 'Schedule a Meeting', url: '#' },
            { id: '2', label: 'View Portfolio', url: '#' },
            { id: '3', label: 'Contact Us', url: '#' },
            { id: '4', label: 'My Services', url: '#services' },
        ],
        themeId: 'cream',
        avatarInitials: name.substring(0, 2).toUpperCase(),
        seo: {
            title: 'My Project | Tap Builder',
            description: desc.length > 150 ? desc.substring(0, 150) + '...' : desc
        }
      };
      setSiteData(newData);
      setStage('editor');
    }, 2000);
  };

  const updateLink = (id: string, field: 'label' | 'url', value: string) => {
    setSiteData(prev => ({
        ...prev,
        links: prev.links.map(l => l.id === id ? { ...l, [field]: value } : l)
    }));
  };

  const addLink = () => {
    setSiteData(prev => ({
        ...prev,
        links: [...prev.links, { id: Date.now().toString(), label: 'New Link', url: '#' }]
    }));
  };

  const removeLink = (id: string) => {
      setSiteData(prev => ({
          ...prev,
          links: prev.links.filter(l => l.id !== id)
      }));
  };

  // Get current theme config safely
  const currentTheme = THEMES[siteData.themeId] || THEMES['cream'];

  if (stage === 'input') return <InputStage onComplete={handleGenerate} />;
  if (stage === 'loading') return <LoadingState />;

  return (
    <div className="h-[calc(100vh-80px)] mt-20 flex flex-col lg:flex-row bg-slate-50 overflow-hidden">

      {/* --- Sidebar Editor --- */}
      <div className="w-full lg:w-[450px] bg-white border-r border-slate-200 flex flex-col shadow-xl z-20">

        {/* Toolbar */}
        <div className="flex items-center border-b border-slate-200 px-6 py-4 gap-6">
            <button 
                onClick={() => setActiveTab('content')}
                className={`pb-1 text-sm font-medium transition-colors ${activeTab === 'content' ? 'text-ink border-b-2 border-jam-red' : 'text-slate-400 hover:text-ink'}`}
            >
                Content
            </button>
            <button 
                onClick={() => setActiveTab('design')}
                className={`pb-1 text-sm font-medium transition-colors ${activeTab === 'design' ? 'text-ink border-b-2 border-jam-red' : 'text-slate-400 hover:text-ink'}`}
            >
                Design
            </button>
            <button 
                onClick={() => setActiveTab('settings')}
                className={`pb-1 text-sm font-medium transition-colors flex items-center gap-1 ${activeTab === 'settings' ? 'text-ink border-b-2 border-jam-red' : 'text-slate-400 hover:text-ink'}`}
            >
                Settings
            </button>
            <div className="ml-auto flex items-center gap-2">
                 {isOffline && <WifiOff size={16} className="text-slate-400" title="Offline Mode: Changes saved locally" />}
                 <Button size="sm" onClick={() => setIsPublished(true)} disabled={isPublished}>
                    {isPublished ? 'Published!' : 'Publish'}
                 </Button>
            </div>
        </div>

        {/* Editor Content */}
        <div className="flex-1 overflow-y-auto p-6 space-y-8">
            {activeTab === 'content' && (
                <>
                    <div className="space-y-4">
                        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Profile</h3>
                        <div>
                            <label className="block text-xs font-medium text-ink mb-1">Display Name</label>
                            <input 
                                value={siteData.name}
                                onChange={(e) => setSiteData({...siteData, name: e.target.value})}
                                className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-ink transition-colors"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-ink mb-1">Bio</label>
                            <textarea 
                                value={siteData.bio}
                                onChange={(e) => setSiteData({...siteData, bio: e.target.value})}
                                className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-ink transition-colors h-24 resize-none"
