                        </div>
                        <h2 className="text-xl font-bold font-serif mb-2">{siteData.name || 'Your Project Name'}</h2>
                        <p className={`text-sm font-light leading-relaxed max-w-md mx-auto opacity-80`}>
                            {siteData.bio || 'Your bio goes here...'}
                        </p>
                    </div>

                    {/* Links */}
                    <div className="px-6 space-y-3 flex-1 max-w-md mx-auto w-full">
                        {siteData.links.map((link) => (
                            <div 
                                key={link.id} 
                                className={`
                                    w-full py-4 px-6 rounded-xl text-sm font-medium flex items-center justify-between shadow-tap-s transition-all duration-300 cursor-pointer hover:scale-[1.03]
                                    ${currentTheme.colors.cardBg}
                                    ${currentTheme.colors.cardBorder}
                                    ${currentTheme.colors.cardText}
                                    ${siteData.themeId === 'dark' || siteData.themeId === 'forest' ? 'border-transparent' : 'border'}
                                `}
                            >
                                {link.label}
                                <ArrowRight size={14} className={`opacity-50 ${currentTheme.colors.accent}`} />
                            </div>
                        ))}
                        {siteData.links.length === 0 && (
                            <div className="text-center py-8 opacity-40 text-xs italic border border-dashed rounded-xl">
                                Add links to see them here
                            </div>
                        )}
                    </div>

                    {/* Branding Footer */}
                    <div className="pb-8 pt-12 text-center">
                        <span className={`text-[10px] font-bold tracking-widest uppercase opacity-30`}>
                            Built with Tap
                        </span>
                    </div>
                </div>

             </div>
        </div>

      </div>
    </div>
  );
};

