  useEffect(() => {
    if (siteData.name) {
      localStorage.setItem('tap_builder_data_v2', JSON.stringify(siteData));
    }
  }, [siteData]);

  // If we loaded data from local storage, jump to editor
  useEffect(() => {
    if (siteData.name && stage === 'input') {
      setStage('editor');
    }
  }, []);

  const handleGenerate = (name: string, desc: string) => {
    setStage('loading');

    // Simulate AI Generation
    setTimeout(() => {
      const newData: SiteData = {
        name: name,
        bio: desc,
        avatarImage: null,
        favicon: null,
        links: [
            { id: '1', label: 'Schedule a Meeting', url: '#', style: { fontSize: 'md', customColor: '', outline: false }, active: true },
            { id: '2', label: 'View Portfolio', url: '#', style: { fontSize: 'md', customColor: '', outline: false }, active: true },
            { id: '3', label: 'Contact Us', url: '#', style: { fontSize: 'md', customColor: '', outline: false }, active: true },
            { id: '4', label: 'My Services', url: '#services', style: { fontSize: 'md', customColor: '', outline: false }, active: true },
        ],
        socials: [],
        themeId: 'cream',
        avatarInitials: name.substring(0, 2).toUpperCase(),
        seo: {
            title: 'My Project | Tap Builder',
            description: desc.length > 150 ? desc.substring(0, 150) + '...' : desc
        }
      };
      setSiteData(newData);
      setStage('editor');
    }, 2000);
  };

  const updateLink = (id: string, field: keyof LinkItem | keyof LinkStyle, value: any) => {
    setSiteData(prev => ({
        ...prev,
        links: prev.links.map(l => {
            if (l.id !== id) return l;
            if (field in l.style) {
                return { ...l, style: { ...l.style, [field]: value } };
            }
            return { ...l, [field]: value };
        })
    }));
  };

  const addLink = () => {
    setSiteData(prev => ({
        ...prev,
        links: [...prev.links, { 
            id: Date.now().toString(), 
            label: 'New Link', 
            url: '#', 
            style: { fontSize: 'md', customColor: '', outline: false },
            active: true 
        }]
    }));
  };

  const removeLink = (id: string) => {
      setSiteData(prev => ({
          ...prev,
          links: prev.links.filter(l => l.id !== id)
      }));
  };

  const addSocial = (platformId: any) => {
     if (siteData.socials.find(s => s.platform === platformId)) return;
     const platform = SOCIAL_PLATFORMS.find(p => p.id === platformId);
     if (!platform) return;

     setSiteData(prev => ({
         ...prev,
         socials: [...prev.socials, { id: Date.now().toString(), platform: platformId, url: '' }]
     }));
  };

  const removeSocial = (id: string) => {
      setSiteData(prev => ({
          ...prev,
          socials: prev.socials.filter(s => s.id !== id)
      }));
  };

  const updateSocial = (id: string, url: string) => {
      setSiteData(prev => ({
          ...prev,
          socials: prev.socials.map(s => s.id === id ? { ...s, url } : s)
      }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'avatarImage' | 'favicon') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSiteData(prev => ({ ...prev, [field]: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  // Drag and Drop Handlers
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedItemIndex(index);
    e.dataTransfer.effectAllowed = "move";
    // Transparent ghost image
    const img = new Image();
    img.src = 'data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7';
    e.dataTransfer.setDragImage(img, 0, 0);
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedItemIndex === null || draggedItemIndex === index) return;

    const newLinks = [...siteData.links];
    const draggedItem = newLinks[draggedItemIndex];
    newLinks.splice(draggedItemIndex, 1);
    newLinks.splice(index, 0, draggedItem);

    setSiteData(prev => ({ ...prev, links: newLinks }));
    setDraggedItemIndex(index);
  };

  const handleDragEnd = () => {
    setDraggedItemIndex(null);
  };

  // Get current theme config safely
  const currentTheme = THEMES[siteData.themeId] || THEMES['cream'];

  if (stage === 'input') return <InputStage onComplete={handleGenerate} />;
  if (stage === 'loading') return <LoadingState />;

  return (
    <div className="h-[calc(100vh-80px)] mt-20 flex flex-col lg:flex-row bg-slate-50 overflow-hidden relative">

      {/* Offline Indicator - Overlay */}
      {isOffline && (
        <div className="absolute top-0 left-0 right-0 z-50 bg-amber-500 text-white text-center py-2 text-sm font-bold shadow-md flex items-center justify-center gap-2">
            <WifiOff size={16} />
            You are currently offline. Changes are saved locally.
        </div>
      )}

      {/* --- Sidebar Editor --- */}
      <div className="w-full lg:w-[480px] bg-white border-r border-slate-200 flex flex-col shadow-xl z-20">

        {/* Toolbar */}
        <div className="flex items-center border-b border-slate-200 px-6 py-4 gap-6 bg-white z-10">
            {['content', 'design', 'settings'].map(tab => (
                 <button 
                    key={tab}
                    onClick={() => setActiveTab(tab as any)}
                    className={`pb-1 text-sm font-medium transition-colors capitalize ${activeTab === tab ? 'text-ink border-b-2 border-jam-red' : 'text-slate-400 hover:text-ink'}`}
                >
                    {tab}
                </button>
            ))}
            <div className="ml-auto flex items-center gap-2">
                 <Button size="sm" onClick={() => setIsPublished(true)} disabled={isPublished}>
                    {isPublished ? 'Published!' : 'Publish'}
                 </Button>
            </div>
        </div>

        {/* Editor Content */}
        <div className="flex-1 overflow-y-auto p-6 space-y-8 no-scrollbar pb-24">
            {activeTab === 'content' && (
                <>
                    {/* Profile Section */}
                    <div className="space-y-4">
                        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Profile</h3>
                        <div className="flex items-start gap-4">
                             <div className="relative group w-20 h-20 shrink-0">
                                 <div className="w-full h-full rounded-full bg-slate-100 border border-slate-200 overflow-hidden flex items-center justify-center text-slate-300">
                                     {siteData.avatarImage ? (
                                         <img src={siteData.avatarImage} alt="Avatar" className="w-full h-full object-cover" />
                                     ) : (
                                         <ImageIcon size={24} />
                                     )}
                                 </div>
                                 <label className="absolute inset-0 bg-black/40 rounded-full flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer">
                                     <Upload size={16} />
                                     <input type="file" accept="image/*" className="hidden" onChange={(e) => handleImageUpload(e, 'avatarImage')} />
                                 </label>
                             </div>
                             <div className="flex-1 space-y-3">
                                 <div>
                                    <label className="block text-xs font-medium text-ink mb-1">Display Name</label>
                                    <input 
                                        value={siteData.name}
                                        onChange={(e) => setSiteData({...siteData, name: e.target.value})}
                                        className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-ink transition-colors"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-ink mb-1">Bio</label>
                                    <textarea 
                                        value={siteData.bio}
                                        onChange={(e) => setSiteData({...siteData, bio: e.target.value})}
                                        className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-ink transition-colors h-20 resize-none"
                                    />
                                </div>
                             </div>
                        </div>
                    </div>

                    {/* Socials Section */}
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Social Icons</h3>
                        </div>
                        <div className="flex gap-2 flex-wrap mb-4">
                             {SOCIAL_PLATFORMS.map(p => (
                                 <button 
                                    key={p.id}
                                    onClick={() => addSocial(p.id)}
                                    className="p-2 border border-slate-200 rounded-lg hover:border-jam-red hover:text-jam-red transition-colors text-slate-500"
                                    title={p.label}
                                 >
                                     <p.icon size={16} />
                                 </button>
                             ))}
                        </div>
                        <div className="space-y-2">
                            {siteData.socials.map((social) => {
                                const platform = SOCIAL_PLATFORMS.find(p => p.id === social.platform);
                                return (
                                    <div key={social.id} className="flex items-center gap-2 animate-fade-up">
                                         <div className="w-8 h-8 rounded bg-slate-100 flex items-center justify-center text-slate-600 shrink-0">
                                             {platform?.icon && <platform.icon size={14} />}
                                         </div>
                                         <input 
                                            value={social.url}
                                            onChange={(e) => updateSocial(social.id, e.target.value)}
                                            placeholder={`Your ${platform?.label} URL`}
                                            className="flex-1 px-3 py-1.5 text-sm bg-slate-50 border border-slate-200 rounded-md focus:outline-none focus:border-ink"
                                         />
                                         <button onClick={() => removeSocial(social.id)} className="text-slate-400 hover:text-red-500">
                                             <X size={14} />
                                         </button>
                                    </div>
                                );
                            })}
                        </div>
                    </div>

                    {/* Links Section */}
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                             <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Links</h3>
                             <button onClick={addLink} className="text-xs flex items-center gap-1 text-jam-red font-medium hover:underline">
                                <Plus size={12} /> Add Link
                             </button>
                        </div>

                        <div className="space-y-3">
                            {siteData.links.map((link, index) => (
                                <div 
                                    key={link.id} 
                                    draggable
                                    onDragStart={(e) => handleDragStart(e, index)}
                                    onDragOver={(e) => handleDragOver(e, index)}
                                    onDragEnd={handleDragEnd}
                                    className={`
                                        p-3 border rounded-lg bg-slate-50 transition-all duration-200
                                        ${draggedItemIndex === index ? 'opacity-50 border-dashed border-slate-400' : 'border-slate-200 hover:border-slate-300'}
                                    `}
                                >
                                    {/* Link Header */}
                                    <div className="flex items-center gap-2 mb-3">
                                        <div className="cursor-grab active:cursor-grabbing text-slate-300 hover:text-slate-500">
                                            <GripVertical size={16} />
                                        </div>
                                        <div className="flex-1 space-y-1">
                                            <input 
                                                value={link.label}
                                                onChange={(e) => updateLink(link.id, 'label', e.target.value)}
                                                className="w-full bg-transparent text-sm font-medium focus:outline-none text-ink placeholder:text-slate-400"
                                                placeholder="Link Title"
                                            />
                                            <input 
                                                value={link.url}
                                                onChange={(e) => updateLink(link.id, 'url', e.target.value)}
                                                className="w-full bg-transparent text-xs text-slate-500 focus:outline-none focus:text-ink placeholder:text-slate-300"
                                                placeholder="https://..."
                                            />
                                        </div>
                                        <button onClick={() => removeLink(link.id)} className="text-slate-400 hover:text-red-500 transition-colors p-1">
                                            <Trash2 size={14} />
                                        </button>
                                    </div>

                                    {/* Link Customization */}
                                    <div className="pt-2 border-t border-slate-200/50 flex items-center gap-4">
                                        <div className="flex items-center gap-2">
                                            <Type size={12} className="text-slate-400" />
                                            <select 
                                                value={link.style.fontSize}
                                                onChange={(e) => updateLink(link.id, 'fontSize', e.target.value)}
                                                className="bg-transparent text-xs text-slate-600 focus:outline-none cursor-pointer"
                                            >
                                                <option value="sm">Small</option>
                                                <option value="md">Medium</option>
                                                <option value="lg">Large</option>
                                            </select>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <Palette size={12} className="text-slate-400" />
                                            <input 
                                                type="color" 
                                                value={link.style.customColor || '#000000'} 
                                                onChange={(e) => updateLink(link.id, 'customColor', e.target.value)}
                                                className="w-4 h-4 rounded-full border-none cursor-pointer"
                                            />
                                        </div>
                                        <label className="flex items-center gap-2 cursor-pointer ml-auto">
                                            <span className="text-xs text-slate-500">Outline</span>
                                            <input 
                                                type="checkbox" 
                                                checked={link.style.outline}
                                                onChange={(e) => updateLink(link.id, 'outline', e.target.checked)}
                                                className="accent-jam-red"
                                            />
                                        </label>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </>
            )}

            {activeTab === 'design' && (
                <div className="space-y-6">
                     <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Choose a Template</h3>
                     <div className="grid grid-cols-2 gap-4">
                        {Object.values(THEMES).map((theme) => (
                            <button 
                                key={theme.id}
                                onClick={() => setSiteData({...siteData, themeId: theme.id})}
                                className={`
                                    relative p-4 rounded-xl border-2 text-left transition-all hover:scale-[1.02]
                                    ${siteData.themeId === theme.id ? 'border-jam-red ring-1 ring-jam-red/20' : 'border-slate-200 hover:border-slate-300'}
                                `}
                            >
                                <div className={`w-full h-20 mb-3 rounded-lg shadow-sm border ${theme.colors.cardBorder} ${theme.colors.bg} relative overflow-hidden`}>
                                   {/* Mini Preview */}
                                   <div className={`absolute top-2 left-2 w-8 h-8 rounded-full ${theme.colors.avatarBg}`}></div>
                                   <div className={`absolute top-12 left-2 w-16 h-2 rounded ${theme.colors.cardBg}`}></div>
                                   <div className={`absolute top-12 left-20 w-8 h-2 rounded ${theme.colors.cardBg}`}></div>
                                </div>
                                <div className="font-medium text-sm text-ink">{theme.name}</div>
                                {siteData.themeId === theme.id && (
                                    <div className="absolute top-2 right-2 w-5 h-5 bg-jam-red rounded-full flex items-center justify-center text-white">
                                        <Check size={10} strokeWidth={3} />
                                    </div>
                                )}
                            </button>
                        ))}
                     </div>
                </div>
            )}

            {activeTab === 'settings' && (
                <div className="space-y-8">
                    <div className="space-y-4">
                        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                            <Search size={14} /> SEO & Social
                        </h3>
                        <div>
                            <label className="block text-xs font-medium text-ink mb-1">Meta Title</label>
                            <input 
                                value={siteData.seo.title}
                                onChange={(e) => setSiteData({...siteData, seo: {...siteData.seo, title: e.target.value}})}
                                className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-ink transition-colors"
                                placeholder="Page Title"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-ink mb-1">Meta Description</label>
                            <textarea 
                                value={siteData.seo.description}
                                onChange={(e) => setSiteData({...siteData, seo: {...siteData.seo, description: e.target.value}})}
                                className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-ink transition-colors h-32 resize-none"
                                placeholder="Description for search engines..."
                            />
                        </div>

                        <div className="pt-4 border-t border-slate-100">
                             <label className="block text-xs font-medium text-ink mb-2">Favicon</label>
                             <div className="flex items-center gap-4">
                                 <div className="w-12 h-12 rounded border border-slate-200 flex items-center justify-center bg-slate-50 overflow-hidden">
                                     {siteData.favicon ? (
                                         <img src={siteData.favicon} alt="Favicon" className="w-8 h-8 object-contain" />
                                     ) : (
                                         <Globe size={20} className="text-slate-300" />
                                     )}
                                 </div>
                                 <label className="px-3 py-1.5 border border-slate-200 rounded-md text-xs font-medium text-slate-600 hover:bg-slate-50 cursor-pointer transition-colors">
                                     Upload Icon
                                     <input type="file" accept="image/x-icon,image/png" className="hidden" onChange={(e) => handleImageUpload(e, 'favicon')} />
                                 </label>
                             </div>
                        </div>
                    </div>

                    {/* Preview Card */}
                    <div className="p-4 bg-slate-50 rounded-xl border border-slate-200">
                        <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Google Search Preview</div>
                        <div className="font-sans">
                            <div className="flex items-center gap-2 mb-1">
                                {siteData.favicon ? (
                                    <img src={siteData.favicon} className="w-4 h-4 rounded-full" />
                                ) : (
                                    <div className="w-4 h-4 bg-slate-200 rounded-full flex items-center justify-center text-[8px] text-slate-500">
                                        {siteData.avatarInitials}
                                    </div>
                                )}
                                <div className="flex flex-col">
                                    <span className="text-xs text-slate-700 font-medium">tap.bio</span>
                                    <span className="text-[10px] text-slate-400">https://tap.bio/{siteData.name.toLowerCase().replace(/\s/g, '')}</span>
                                </div>
                            </div>
                            <h4 className="text-blue-700 text-lg hover:underline cursor-pointer truncate">
                                {siteData.seo.title || siteData.name}
                            </h4>
                            <p className="text-sm text-slate-600 line-clamp-2">
                                {siteData.seo.description || siteData.bio}
                            </p>
                        </div>
                    </div>
                </div>
            )}
        </div>
      </div>

      {/* --- Preview Area --- */}
      <div className="flex-1 bg-slate-100/50 flex flex-col items-center justify-center relative overflow-hidden transition-all duration-300">

        {/* Device Toggle */}
        <div className="absolute top-6 z-30 bg-white border border-slate-200 rounded-full p-1 flex items-center shadow-sm">
            <button 
                onClick={() => setPreviewDevice('mobile')}
                className={`p-2 rounded-full transition-all ${previewDevice === 'mobile' ? 'bg-slate-100 text-ink' : 'text-slate-400 hover:text-ink'}`}
                title="Mobile View"
            >
                <Smartphone size={18} />
            </button>
            <button 
                onClick={() => setPreviewDevice('desktop')}
                className={`p-2 rounded-full transition-all ${previewDevice === 'desktop' ? 'bg-slate-100 text-ink' : 'text-slate-400 hover:text-ink'}`}
                title="Desktop View"
            >
                <Monitor size={18} />
            </button>
        </div>

        {/* Background Dots */}
        <div className="absolute inset-0 bg-dot-pattern opacity-50 pointer-events-none" />

        {isPublished && (
             <div className="absolute top-24 left-1/2 -translate-x-1/2 bg-ink text-white px-6 py-2 rounded-full shadow-xl flex items-center gap-3 animate-fade-up z-30">
                <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse" />
                Your site is live!
                <button className="text-slate-400 hover:text-white"><Share2 size={16} /></button>
            </div>
        )}

        {/* Device Frame */}
        <div 
            className={`
                bg-white shadow-2xl relative overflow-hidden z-10 transition-all duration-500 ease-in-out flex flex-col
                ${previewDevice === 'mobile' ? 'w-[340px] h-[680px] rounded-[40px] border-[8px] border-slate-900' : 'w-[90%] max-w-5xl h-[85%] rounded-xl border border-slate-200 mt-12'}
            `}
        >
             {/* Desktop Browser Bar */}
             {previewDevice === 'desktop' && (
                 <div className="h-10 bg-slate-50 border-b border-slate-200 flex items-center px-4 gap-2 shrink-0">
                     <div className="flex gap-1.5">
                         <div className="w-3 h-3 rounded-full bg-red-400/80"></div>
                         <div className="w-3 h-3 rounded-full bg-amber-400/80"></div>
                         <div className="w-3 h-3 rounded-full bg-green-400/80"></div>
                     </div>
                     <div className="flex-1 text-center text-xs text-slate-400 font-mono bg-white mx-4 py-1 rounded border border-slate-200 flex items-center justify-center gap-2">
                         {siteData.favicon && <img src={siteData.favicon} className="w-3 h-3" />}
                         tap.bio/{siteData.name.toLowerCase().replace(/\s/g, '')}
                     </div>
                 </div>
             )}

             {/* Dynamic Content */}
             <div className={`w-full h-full flex flex-col overflow-y-auto no-scrollbar transition-colors duration-300 ${currentTheme.colors.bg} ${currentTheme.colors.text}`}>

                <div className={`
                    w-full mx-auto 
                    ${previewDevice === 'desktop' ? 'max-w-3xl py-16' : 'py-12'}
                `}>
                    {/* Header */}
                    <div className="px-6 text-center mb-8 animate-fade-up">
                        <div className={`w-24 h-24 mx-auto mb-6 rounded-full flex items-center justify-center text-4xl font-serif italic shadow-sm transition-colors duration-300 overflow-hidden ${currentTheme.colors.avatarBg} ${currentTheme.colors.avatarText}`}>
                            {siteData.avatarImage ? (
                                <img src={siteData.avatarImage} alt="Avatar" className="w-full h-full object-cover" />
                            ) : (
                                siteData.avatarInitials
                            )}
                        </div>
                        <h2 className="text-xl font-bold font-serif mb-2">{siteData.name || 'Your Project Name'}</h2>
                        <p className={`text-sm font-light leading-relaxed max-w-md mx-auto opacity-80`}>
                            {siteData.bio || 'Your bio goes here...'}
                        </p>

                        {/* Social Icons in Header */}
                        {siteData.socials.length > 0 && (
                            <div className="flex items-center justify-center gap-4 mt-6">
                                {siteData.socials.map(social => {
                                    const platform = SOCIAL_PLATFORMS.find(p => p.id === social.platform);
                                    if (!platform) return null;
                                    return (
                                        <a key={social.id} href={social.url} target="_blank" rel="noreferrer" className={`hover:opacity-70 transition-opacity ${currentTheme.colors.text}`}>
                                            <platform.icon size={20} />
                                        </a>
                                    );
                                })}
                            </div>
                        )}
                    </div>

                    {/* Links */}
                    <div className="px-6 space-y-3 flex-1 max-w-md mx-auto w-full">
                        {siteData.links.map((link, idx) => (
                            <div 
                                key={link.id} 
                                className={`
                                    w-full py-4 px-6 rounded-xl font-medium flex items-center justify-between shadow-tap-s transition-all duration-300 cursor-pointer hover:scale-[1.03] hover:-translate-y-0.5 animate-fade-up
                                    ${currentTheme.colors.cardBg}
                                    ${currentTheme.colors.cardText}
                                    ${link.style.outline ? `border-2` : 'border'}
                                    ${siteData.themeId === 'dark' || siteData.themeId === 'forest' ? 'border-transparent' : 'border-slate-200'}
                                `}
                                style={{
                                    animationDelay: `${idx * 100}ms`,
                                    fontSize: link.style.fontSize === 'sm' ? '0.875rem' : link.style.fontSize === 'lg' ? '1.125rem' : '1rem',
                                    color: link.style.customColor || undefined,
                                    borderColor: link.style.customColor || undefined
                                }}
                            >
                                {link.label}
                                <ArrowRight size={14} className={`opacity-50 ${currentTheme.colors.accent}`} style={{ color: link.style.customColor || undefined }} />
                            </div>
                        ))}
                        {siteData.links.length === 0 && (
                            <div className="text-center py-8 opacity-40 text-xs italic border border-dashed rounded-xl">
                                Add links to see them here
                            </div>
                        )}
                    </div>

                    {/* Branding Footer */}
                    <div className="pb-8 pt-12 text-center">
                        <span className={`text-[10px] font-bold tracking-widest uppercase opacity-30`}>
                            Built with Tap
                        </span>
                    </div>
                </div>

             </div>
        </div>

      </div>
    </div>
  );
};

