                                `}
                            >
                                <div className={`w-full h-20 mb-3 rounded-lg shadow-sm border ${theme.colors.cardBorder} ${theme.colors.bg} relative overflow-hidden`}>
                                   {/* Mini Preview */}
                                   <div className={`absolute top-2 left-2 w-8 h-8 rounded-full ${theme.colors.avatarBg}`}></div>
                                   <div className={`absolute top-12 left-2 w-16 h-2 rounded ${theme.colors.cardBg}`}></div>
                                   <div className={`absolute top-12 left-20 w-8 h-2 rounded ${theme.colors.cardBg}`}></div>
                                </div>
                                <div className="font-medium text-sm text-ink">{theme.name}</div>
                                {siteData.themeId === theme.id && (
                                    <div className="absolute top-2 right-2 w-5 h-5 bg-jam-red rounded-full flex items-center justify-center text-white">
                                        <Check size={10} strokeWidth={3} />
                                    </div>
                                )}
                            </button>
                        ))}
                     </div>
                </div>
            )}

            {activeTab === 'settings' && (
                <div className="space-y-8">
                    <div className="space-y-4">
                        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                            <Search size={14} /> SEO & Social
                        </h3>
                        <div>
                            <label className="block text-xs font-medium text-ink mb-1">Meta Title</label>
                            <input 
                                value={siteData.seo.title}
                                onChange={(e) => setSiteData({...siteData, seo: {...siteData.seo, title: e.target.value}})}
                                className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-ink transition-colors"
                                placeholder="Page Title"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-ink mb-1">Meta Description</label>
                            <textarea 
                                value={siteData.seo.description}
                                onChange={(e) => setSiteData({...siteData, seo: {...siteData.seo, description: e.target.value}})}
                                className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-ink transition-colors h-32 resize-none"
                                placeholder="Description for search engines..."
                            />
                        </div>

                        <div className="pt-4 border-t border-slate-100">
                             <label className="block text-xs font-medium text-ink mb-2">Favicon</label>
                             <div className="flex items-center gap-4">
                                 <div className="w-12 h-12 rounded border border-slate-200 flex items-center justify-center bg-slate-50 overflow-hidden">
                                     {siteData.favicon ? (
                                         <img src={siteData.favicon} alt="Favicon" className="w-8 h-8 object-contain" />
                                     ) : (
                                         <Globe size={20} className="text-slate-300" />
                                     )}
                                 </div>
                                 <label className="px-3 py-1.5 border border-slate-200 rounded-md text-xs font-medium text-slate-600 hover:bg-slate-50 cursor-pointer transition-colors">
                                     Upload Icon
                                     <input type="file" accept="image/x-icon,image/png" className="hidden" onChange={(e) => handleImageUpload(e, 'favicon')} />
                                 </label>
                             </div>
                        </div>
                    </div>

                    {/* Preview Card */}
                    <div className="p-4 bg-slate-50 rounded-xl border border-slate-200">
                        <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Google Search Preview</div>
                        <div className="font-sans">
                            <div className="flex items-center gap-2 mb-1">
                                {siteData.favicon ? (
                                    <img src={siteData.favicon} className="w-4 h-4 rounded-full" />
                                ) : (
                                    <div className="w-4 h-4 bg-slate-200 rounded-full flex items-center justify-center text-[8px] text-slate-500">
                                        {siteData.avatarInitials}
                                    </div>
                                )}
                                <div className="flex flex-col">
                                    <span className="text-xs text-slate-700 font-medium">tap.bio</span>
                                    <span className="text-[10px] text-slate-400">https://tap.bio/{siteData.name.toLowerCase().replace(/\s/g, '')}</span>
                                </div>
                            </div>
                            <h4 className="text-blue-700 text-lg hover:underline cursor-pointer truncate">
                                {siteData.seo.title || siteData.name}
                            </h4>
                            <p className="text-sm text-slate-600 line-clamp-2">
                                {siteData.seo.description || siteData.bio}
                            </p>
                        </div>
                    </div>
                </div>
            )}
        </div>
      </div>

      {/* --- Preview Area --- */}
      <div className="flex-1 bg-slate-100/50 flex flex-col items-center justify-center relative overflow-hidden transition-all duration-300">

        {/* Device Toggle */}
        <div className="absolute top-6 z-30 bg-white border border-slate-200 rounded-full p-1 flex items-center shadow-sm">
            <button 
                onClick={() => setPreviewDevice('mobile')}
                className={`p-2 rounded-full transition-all ${previewDevice === 'mobile' ? 'bg-slate-100 text-ink' : 'text-slate-400 hover:text-ink'}`}
                title="Mobile View"
            >
                <Smartphone size={18} />
            </button>
            <button 
                onClick={() => setPreviewDevice('desktop')}
                className={`p-2 rounded-full transition-all ${previewDevice === 'desktop' ? 'bg-slate-100 text-ink' : 'text-slate-400 hover:text-ink'}`}
                title="Desktop View"
            >
                <Monitor size={18} />
            </button>
        </div>

        {/* Background Dots */}
        <div className="absolute inset-0 bg-dot-pattern opacity-50 pointer-events-none" />

        {isPublished && (
             <div className="absolute top-24 left-1/2 -translate-x-1/2 bg-ink text-white px-6 py-2 rounded-full shadow-xl flex items-center gap-3 animate-fade-up z-30">
                <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse" />
                Your site is live!
                <button className="text-slate-400 hover:text-white"><Share2 size={16} /></button>
            </div>
        )}

        {/* Device Frame */}
        <div 
            className={`
                bg-white shadow-2xl relative overflow-hidden z-10 transition-all duration-500 ease-in-out flex flex-col
                ${previewDevice === 'mobile' ? 'w-[340px] h-[680px] rounded-[40px] border-[8px] border-slate-900' : 'w-[90%] max-w-5xl h-[85%] rounded-xl border border-slate-200 mt-12'}
            `}
        >
             {/* Desktop Browser Bar */}
             {previewDevice === 'desktop' && (
                 <div className="h-10 bg-slate-50 border-b border-slate-200 flex items-center px-4 gap-2 shrink-0">
                     <div className="flex gap-1.5">
                         <div className="w-3 h-3 rounded-full bg-red-400/80"></div>
                         <div className="w-3 h-3 rounded-full bg-amber-400/80"></div>
                         <div className="w-3 h-3 rounded-full bg-green-400/80"></div>
                     </div>
                     <div className="flex-1 text-center text-xs text-slate-400 font-mono bg-white mx-4 py-1 rounded border border-slate-200 flex items-center justify-center gap-2">
                         {siteData.favicon && <img src={siteData.favicon} className="w-3 h-3" />}
                         tap.bio/{siteData.name.toLowerCase().replace(/\s/g, '')}
                     </div>
                 </div>
             )}

             {/* Dynamic Content */}
             <div className={`w-full h-full flex flex-col overflow-y-auto no-scrollbar transition-colors duration-300 ${currentTheme.colors.bg} ${currentTheme.colors.text}`}>

                <div className={`
                    w-full mx-auto 
                    ${previewDevice === 'desktop' ? 'max-w-3xl py-16' : 'py-12'}
                `}>
                    {/* Header */}
                    <div className="px-6 text-center mb-8 animate-fade-up">
                        <div className={`w-24 h-24 mx-auto mb-6 rounded-full flex items-center justify-center text-4xl font-serif italic shadow-sm transition-colors duration-300 overflow-hidden ${currentTheme.colors.avatarBg} ${currentTheme.colors.avatarText}`}>
                            {siteData.avatarImage ? (
                                <img src={siteData.avatarImage} alt="Avatar" className="w-full h-full object-cover" />
                            ) : (
                                siteData.avatarInitials
                            )}
                        </div>
                        <h2 className="text-xl font-bold font-serif mb-2">{siteData.name || 'Your Project Name'}</h2>
                        <p className={`text-sm font-light leading-relaxed max-w-md mx-auto opacity-80`}>
                            {siteData.bio || 'Your bio goes here...'}
                        </p>

                        {/* Social Icons in Header */}
                        {siteData.socials.length > 0 && (
                            <div className="flex items-center justify-center gap-4 mt-6">
                                {siteData.socials.map(social => {
                                    const platform = SOCIAL_PLATFORMS.find(p => p.id === social.platform);
                                    if (!platform) return null;
                                    return (
                                        <a key={social.id} href={social.url} target="_blank" rel="noreferrer" className={`hover:opacity-70 transition-opacity ${currentTheme.colors.text}`}>
                                            <platform.icon size={20} />
                                        </a>
                                    );
                                })}
                            </div>
                        )}
                    </div>

                    {/* Links */}
                    <div className="px-6 space-y-3 flex-1 max-w-md mx-auto w-full">
                        {siteData.links.map((link, idx) => (
                            <div 
                                key={link.id} 
                                className={`
                                    w-full py-4 px-6 rounded-xl font-medium flex items-center justify-between shadow-tap-s transition-all duration-300 cursor-pointer hover:scale-[1.03] hover:-translate-y-0.5 animate-fade-up
                                    ${currentTheme.colors.cardBg}
                                    ${currentTheme.colors.cardText}
                                    ${link.style.outline ? `border-2` : 'border'}
                                    ${siteData.themeId === 'dark' || siteData.themeId === 'forest' ? 'border-transparent' : 'border-slate-200'}
                                `}
                                style={{
                                    animationDelay: `${idx * 100}ms`,
                                    fontSize: link.style.fontSize === 'sm' ? '0.875rem' : link.style.fontSize === 'lg' ? '1.125rem' : '1rem',
                                    color: link.style.customColor || undefined,
                                    borderColor: link.style.customColor || undefined
                                }}
                            >
                                {link.label}
                                <ArrowRight size={14} className={`opacity-50 ${currentTheme.colors.accent}`} style={{ color: link.style.customColor || undefined }} />
                            </div>
                        ))}
                        {siteData.links.length === 0 && (
                            <div className="text-center py-8 opacity-40 text-xs italic border border-dashed rounded-xl">
                                Add links to see them here
                            </div>
                        )}
                    </div>

                    {/* Branding Footer */}
                    <div className="pb-8 pt-12 text-center">
                        <span className={`text-[10px] font-bold tracking-widest uppercase opacity-30`}>
                            Built with Tap
                        </span>
                    </div>
                </div>

             </div>
        </div>

      </div>
    </div>
  );
};

export default Builder;

import React, { useState, useEffect } from 'react';
import { Menu, X } from 'lucide-react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import Button from './ui/Button';

const Navbar: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavClick = (hash: string) => {
    setMobileMenuOpen(false);
    if (location.pathname !== '/') {
        navigate('/' + hash);
    } else {
        const element = document.getElementById(hash.replace('#', ''));
        if (element) {
            element.scrollIntoView({ behavior: 'smooth' });
        }
    }
  };

  const handleJoinBeta = () => {
      navigate('/login');
      setMobileMenuOpen(false);
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ease-out px-4 md:px-6 pt-4`}>
      <div className={`mx-auto flex items-center justify-between transition-all duration-500 ease-[cubic-bezier(0.25,0.1,0.25,1)] ${
        scrolled 
          ? 'max-w-5xl bg-white/70 backdrop-blur-xl border border-white/40 shadow-tap-m rounded-full py-2.5 px-6' 
          : 'max-w-7xl bg-transparent py-4 px-0'
      }`}>

        {/* Logo */}
        <Link to="/" className="flex items-center gap-3 cursor-pointer group" onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}>
          <div className="relative w-8 h-8">
             <svg width="100%" height="100%" viewBox="0 0 32 32" fill="none" xmlns="http://www.w3.org/2000/svg" className="text-jam-red transition-transform duration-500 group-hover:rotate-6">
                {/* Vertical Stem */}
                <rect x="11" y="8" width="10" height="22" rx="5" stroke="currentColor" strokeWidth="2.5" className="fill-cream" />
                {/* Horizontal Top */}
                <rect x="2" y="2" width="28" height="10" rx="5" stroke="currentColor" strokeWidth="2.5" className="fill-cream" />
             </svg>
          </div>
          <span className="text-2xl font-bold tracking-tight text-ink font-serif">Tap.</span>
        </Link>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center gap-1">
          <div className={`flex items-center gap-1 mr-4 px-2 py-1 rounded-full transition-all ${scrolled ? 'bg-slate-100/50 border border-white/20' : ''}`}>
              <button onClick={() => handleNavClick('#features')} className="px-4 py-1.5 text-sm font-medium text-slate-600 hover:text-ink transition-colors rounded-full hover:bg-white/50">Features</button>
              <button onClick={() => handleNavClick('#pricing')} className="px-4 py-1.5 text-sm font-medium text-slate-600 hover:text-ink transition-colors rounded-full hover:bg-white/50">Pricing</button>
              <button onClick={() => handleNavClick('#blog')} className="px-4 py-1.5 text-sm font-medium text-slate-600 hover:text-ink transition-colors rounded-full hover:bg-white/50">Blog</button>
          </div>

          <Link to="/login" className="text-sm font-medium text-slate-600 hover:text-ink transition-colors font-sans mr-4">Login</Link>

          <Button variant="primary" size="sm" onClick={handleJoinBeta} className={scrolled ? 'shadow-none' : ''}>
              Get Started
          </Button>
        </div>

        {/* Mobile Menu Toggle */}
        <button 
          className="md:hidden text-ink p-2 rounded-full hover:bg-slate-100 active:scale-95 transition-all"
          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
        >
          {mobileMenuOpen ? <X size={20} /> : <Menu size={20} />}
        </button>
      </div>

      {/* Mobile Menu */}
      <div className={`absolute top-20 left-4 right-4 bg-white/90 backdrop-blur-xl border border-white/40 rounded-3xl p-6 shadow-2xl md:hidden flex flex-col gap-2 transition-all duration-300 ease-[cubic-bezier(0.34,1.56,0.64,1)] origin-top ${
        mobileMenuOpen 
          ? 'opacity-100 scale-100 translate-y-0 pointer-events-auto' 
          : 'opacity-0 scale-95 -translate-y-4 pointer-events-none'
      }`}>
         <button onClick={() => handleNavClick('#features')} className="text-left text-lg font-medium text-ink py-3 px-4 rounded-xl hover:bg-slate-50 transition-colors">Features</button>
         <button onClick={() => handleNavClick('#pricing')} className="text-left text-lg font-medium text-ink py-3 px-4 rounded-xl hover:bg-slate-50 transition-colors">Pricing</button>
         <button onClick={() => handleNavClick('#blog')} className="text-left text-lg font-medium text-ink py-3 px-4 rounded-xl hover:bg-slate-50 transition-colors">Blog</button>
         <div className="h-px bg-slate-100 my-2"></div>
         <Link to="/login" className="text-lg font-medium text-ink py-3 px-4 rounded-xl hover:bg-slate-50 transition-colors" onClick={() => setMobileMenuOpen(false)}>Login</Link>

        <div className="pt-2">
            <Button 
                fullWidth 
                variant="primary" 
                onClick={handleJoinBeta}
            >
                Get Started
            </Button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
